const item = $input.item.json;
const rawText = item.llm_response || item.output || item.text || '';

try {
  let cleanText = rawText.trim();
  if (cleanText.startsWith('```')) {
    cleanText = cleanText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  }
  const parsed = JSON.parse(cleanText);
  return { json: { ...item, ...parsed, parse_error: false } };
} catch (err) {
  return {
    json: {
      ...item,
      parse_error: true,
      raw_response: rawText,
      outcome: 'error',
      score: null,
      criteria_scores: null,
      parse_error_message: err.message
    }
  };
}

// T1: Read evaluation_id, test_run_id, evaluator_config_id from webhook payload.
// triggered_by is audit-only - never branch on it.
const input = $('When Executed by Another Workflow').first().json;
const evaluationId = input.evaluation_id || null;
const testRunId = input.test_run_id || null;
const evaluatorConfigId = input.evaluator_config_id || null;
const triggeredBy = input.triggered_by || 'unknown';
// T5d: extract run_analyzer flag (default true if not provided)
const runAnalyzer = input.run_analyzer ?? input.body?.run_analyzer ?? true;
if (!evaluationId) throw new Error('[T1] evaluation_id is required in webhook payload');
if (!testRunId) throw new Error('[T1] test_run_id is required in webhook payload');
console.log('[T1] evaluation_id=' + evaluationId + ' test_run_id=' + testRunId + ' run_analyzer=' + runAnalyzer);
return { json: { evaluation_id: evaluationId, test_run_id: testRunId, evaluator_config_id: evaluatorConfigId, triggered_by: triggeredBy, run_analyzer: runAnalyzer } };

const raw = $input.first().json.text || $input.first().json.content || '';
let cleaned = raw.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
const testRunId = $('PG Aggregate').first().json.analysis_context?.test_run_id;
if (start === -1 || end === -1) return [{ json: { success: false, error: 'NO_JSON_FOUND', raw: raw.substring(0,500), test_run_id: testRunId } }];
try {
  const parsed = JSON.parse(cleaned.substring(start, end + 1));
  const required = ['summary','top_issues','suggestions','overall_assessment'];
  const missing = required.filter(f => !(f in parsed));
  if (missing.length > 0) return [{ json: { success: false, error: 'MISSING_FIELDS', missing, test_run_id: testRunId } }];
  parsed.top_issues = Array.isArray(parsed.top_issues) ? parsed.top_issues : [];
  parsed.suggestions = Array.isArray(parsed.suggestions) ? parsed.suggestions : [];
  parsed.strengths = Array.isArray(parsed.strengths) ? parsed.strengths : [];
  return [{ json: { success: true, analysis_report: parsed, analyzed_at: new Date().toISOString(), issues_count: parsed.top_issues.length, suggestions_count: parsed.suggestions.length, overall_assessment: parsed.overall_assessment, test_run_id: testRunId } }];
} catch (e) {
  return [{ json: { success: false, error: 'PARSE_ERROR', message: e.message, test_run_id: testRunId } }];
}

// T2 + T4: Build dynamic system prompt with criteria taxonomy.
// T4: COALESCE criteria_snapshot / llm_config_snapshot for backwards compat.
const config = $('Fetch Evaluator Config').first().json;
const createEvalRow = $('Create Evaluation').first().json;
const evaluationId = createEvalRow.evaluation_id;
if (!evaluationId) throw new Error('[Build Dynamic System Prompt] No evaluation_id from Create Evaluation');
const rawCriteria = createEvalRow.criteria_snapshot || config.criteria;
if (!rawCriteria || (!Array.isArray(rawCriteria) && typeof rawCriteria !== 'object')) throw new Error('No criteria found: ' + config.id);
const llmConfig = createEvalRow.llm_config_snapshot || config.llm_config || {};
const template = config.system_prompt_template;
if (!template) throw new Error('No system_prompt_template: ' + config.id);
let coreCriteria = [], domainCriteria = [];
if (Array.isArray(rawCriteria)) { coreCriteria = rawCriteria; }
else if (typeof rawCriteria === 'object' && rawCriteria !== null) { coreCriteria = rawCriteria.core || []; domainCriteria = rawCriteria.domain || []; }
const allCriteria = [...coreCriteria, ...domainCriteria];
if (allCriteria.length === 0) throw new Error('[Build] Zero criteria');
const invalid = allCriteria.filter(c => !c.name || typeof c.name !== 'string' || c.name.trim() === '');
if (invalid.length > 0) throw new Error('[REQ-T2.7] Missing criterion names: ' + JSON.stringify(invalid));
const CRIT = 'CRITERIA_SECTION_HERE';
const SCORE = 'SCORES_TEMPLATE_HERE';
const buildSection = (criteria, label) => criteria.map((c, i) => [(label ? label + ' ' : '') + (i+1) + '. **' + c.name.replace(/_/g,' ').toUpperCase() + '** (weight: ' + (c.weight != null ? c.weight : (c.weight_default != null ? c.weight_default : 1.0)) + ')', '   ' + (c.description || ''), c.scoring_guide ? '   Scale: ' + c.scoring_guide : ''].filter(Boolean).join('\n')).join('\n\n');
let criteriaSection = domainCriteria.length > 0 ? buildSection(coreCriteria,'[CORE]') + '\n\n' + buildSection(domainCriteria,'[DOMAIN]') : buildSection(coreCriteria,'');
const scoresTemplate = {};
allCriteria.forEach(c => { scoresTemplate[c.name] = 0; });
const hasWeights = allCriteria.some(c => (c.weight != null ? c.weight : (c.weight_default != null ? c.weight_default : 1.0)) !== 1.0);
const weightNote = hasWeights ? '\n\n**SCORING**: Final score = SUM(score_i * weight_i) / SUM(weight_i).' : '';
let systemPrompt = template;
if (template.indexOf(CRIT) !== -1) systemPrompt = systemPrompt.split(CRIT).join(criteriaSection + weightNote);
if (systemPrompt.indexOf(SCORE) !== -1) systemPrompt = systemPrompt.split(SCORE).join(JSON.stringify(scoresTemplate, null, 2));
const battles = $('Get Pending Evaluations').all();
return battles.map(battle => ({ json: { ...battle.json, evaluation_id: evaluationId, evaluator_config_id: config.id, evaluator_name: config.name, dynamic_system_prompt: systemPrompt, criteria_names: allCriteria.map(c => c.name), criteria_with_weights: allCriteria.map(c => ({ name: c.name, weight: c.weight != null ? c.weight : (c.weight_default != null ? c.weight_default : 1.0) })), expected_scores_shape: scoresTemplate, success_config: config.success_config, llm_config: llmConfig } }));

