  const unknown = criteriaNames.filter(n => !knownNames.includes(n));
  if (unknown.length > 0) throw new Error('[REQ-T2.7] Unknown criteria: ' + unknown.join(', ') + ' for evaluation ' + item.evaluation_id);
}
console.log('[Validate Criteria Names] ' + criteriaNames.length + ' criteria OK for evaluation ' + item.evaluation_id);
return { json: item };

// T3: Track model_used and tokens_used.
const item = $input.first().json;
const llmConfig = item.llm_config || {};
const tokenUsage = item.tokenUsage || item.usage || {};
const tokensUsed = tokenUsage.totalTokens || tokenUsage.total_tokens || ((tokenUsage.promptTokens || 0) + (tokenUsage.completionTokens || 0)) || null;
const primaryModel = llmConfig.judge?.model || 'models/gemini-3-flash-preview';
const fallbackModel = llmConfig.judge?.fallback?.model || 'google/gemini-3-flash-preview';
const modelUsed = item._usedFallback ? (fallbackModel + ' (fallback)') : primaryModel;
console.log('[LLM Result Tracker] evaluation_id=' + item.evaluation_id + ' model=' + modelUsed + ' tokens=' + tokensUsed);
return { json: { ...item, model_used: modelUsed, tokens_used: tokensUsed } };

// T2/REQ-T2.7: Merge criteria_definitions into items, validate all names exist.
const buildItems = $('Build Dynamic System Prompt').all();
const definitionsRows = $('Fetch Criteria Definitions').all();
const definitionsMap = {};
for (const row of definitionsRows) definitionsMap[row.json.name] = row.json;
const knownNames = Object.keys(definitionsMap);
return buildItems.map(item => {
  const criteriaNames = item.json.criteria_names || [];
  const unknown = criteriaNames.filter(n => !definitionsMap[n]);
  if (unknown.length > 0) throw new Error('[REQ-T2.7] Unknown criteria: ' + unknown.join(', ') + ' for evaluation ' + item.json.evaluation_id);
  const enrichedWeights = (item.json.criteria_with_weights || []).map(cw => {
    const def = definitionsMap[cw.name] || {};
    return { name: cw.name, weight: cw.weight != null ? cw.weight : (def.weight_default != null ? def.weight_default : 1.0), description: def.description || '', scoring_guide: def.scoring_guide || '', category: def.category || '', domain_type: def.domain_type || '' };
  });
  return { json: { ...item.json, criteria_with_weights: enrichedWeights, known_criteria_names: knownNames } };
});

